import { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import type { SupabaseClient } from "@supabase/supabase-js";
import { StepIntro } from "./steps/StepIntro";
import { StepQualification } from "./steps/StepQualification";
import { StepBenefits } from "./steps/StepBenefits";
import { StepAvailability } from "./steps/StepAvailability";
import { StepContact } from "./steps/StepContact";
import { StepSuccess } from "./steps/StepSuccess";
import { StepExperience } from "./steps/StepExperience";
import { StepDriversLicense } from "./steps/StepDriversLicense";
import { ProgressBar } from "./ProgressBar";

interface RecruitmentWizardProps {
  clientId: string;
  tradeType: string;
  supabaseClient: SupabaseClient;
}

export interface WizardData {
  qualification: string;
  experience: string;
  driversLicense: string;
  benefits: string[];
  availability: string;
  name: string;
  phone: string;
  consent: boolean;
}

const TOTAL_STEPS = 7;

const slideVariants = {
  enter: (direction: number) => ({
    x: direction > 0 ? 300 : -300,
    opacity: 0,
  }),
  center: {
    x: 0,
    opacity: 1,
  },
  exit: (direction: number) => ({
    x: direction > 0 ? -300 : 300,
    opacity: 0,
  }),
};

export const RecruitmentWizard = ({ clientId, tradeType, supabaseClient }: RecruitmentWizardProps) => {
  const [step, setStep] = useState(0);
  const [direction, setDirection] = useState(1);
  const [loading, setLoading] = useState(false);
  const [submitted, setSubmitted] = useState(false);
  const [data, setData] = useState<WizardData>({
    qualification: "",
    experience: "",
    driversLicense: "",
    benefits: [],
    availability: "",
    name: "",
    phone: "",
    consent: false,
  });

  const next = () => {
    setDirection(1);
    setStep((s) => Math.min(s + 1, TOTAL_STEPS));
  };

  const back = () => {
    setDirection(-1);
    setStep((s) => Math.max(s - 1, 0));
  };

  const updateData = (partial: Partial<WizardData>) => {
    setData((prev) => ({ ...prev, ...partial }));
  };

  const submit = async () => {
    setLoading(true);
    try {
      const { error } = await supabaseClient.from("recruitment_leads").insert({
        client_id: clientId,
        trade_type: tradeType,
        qualification: data.qualification,
        years_of_experience: data.experience,
        drivers_license_class: data.driversLicense,
        benefits_selected: data.benefits,
        availability: data.availability,
        candidate_name: data.name,
        candidate_phone: data.phone,
      });
      if (error) throw error;
      setSubmitted(true);
      setStep(TOTAL_STEPS);
    } catch (err) {
      console.error("Submission error:", err);
    } finally {
      setLoading(false);
    }
  };

  const renderStep = () => {
    if (submitted) return <StepSuccess tradeType={tradeType} />;
    switch (step) {
      case 0:
        return <StepIntro tradeType={tradeType} onNext={next} />;
      case 1:
        return <StepQualification value={data.qualification} onChange={(v) => updateData({ qualification: v })} onNext={next} onBack={back} />;
      case 2:
        return <StepExperience value={data.experience} onChange={(v) => updateData({ experience: v })} onNext={next} onBack={back} />;
      case 3:
        return <StepDriversLicense value={data.driversLicense} onChange={(v) => updateData({ driversLicense: v })} onNext={next} onBack={back} />;
      case 4:
        return <StepBenefits value={data.benefits} onChange={(v) => updateData({ benefits: v })} onNext={next} onBack={back} />;
      case 5:
        return <StepAvailability value={data.availability} onChange={(v) => updateData({ availability: v })} onNext={next} onBack={back} />;
      case 6:
        return <StepContact data={data} onChange={updateData} onSubmit={submit} onBack={back} loading={loading} />;
      default:
        return null;
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-background p-4">
      <div className="w-full max-w-lg">
        <motion.div layout transition={{ layout: { duration: 0.3, ease: "easeInOut" } }} className="bg-card rounded-2xl shadow-xl overflow-hidden">
          {!submitted && <ProgressBar current={step} total={TOTAL_STEPS} />}
          <div className="p-6 sm:p-8 flex flex-col">
            <AnimatePresence mode="popLayout" custom={direction}>
              <motion.div
                key={step + (submitted ? "-done" : "")}
                custom={direction}
                variants={slideVariants}
                initial="enter"
                animate="center"
                exit="exit"
                transition={{ duration: 0.3, ease: "easeInOut" }}
                className="flex flex-col"
              >
                {renderStep()}
              </motion.div>
            </AnimatePresence>
          </div>
        </motion.div>
        <p className="text-center text-xs text-muted-foreground mt-4 opacity-60">
          Powered by professionelles Recruiting
        </p>
      </div>
    </div>
  );
};

import { motion } from "framer-motion";

interface ProgressBarProps {
  current: number;
  total: number;
}

export const ProgressBar = ({ current, total }: ProgressBarProps) => {
  const progress = (current / total) * 100;

  return (
    <div className="h-1.5 bg-secondary w-full">
      <motion.div
        className="h-full bg-primary rounded-r-full"
        initial={{ width: 0 }}
        animate={{ width: `${progress}%` }}
        transition={{ duration: 0.4, ease: "easeOut" }}
      />
    </div>
  );
};

import { cn } from "@/lib/utils";
import { motion } from "framer-motion";

interface SelectionCardProps {
  label: string;
  icon?: string;
  selected: boolean;
  onClick: () => void;
}

export const SelectionCard = ({ label, icon, selected, onClick }: SelectionCardProps) => {
  return (
    <motion.button
      whileTap={{ scale: 0.96 }}
      onClick={onClick}
      className={cn(
        "w-full py-4 px-5 rounded-xl text-left text-lg font-medium transition-all duration-200 border-2",
        selected
          ? "bg-primary text-primary-foreground border-primary shadow-md"
          : "bg-card text-card-foreground border-border hover:border-primary/40"
      )}
    >
      {icon && <span className="mr-3">{icon}</span>}
      {label}
    </motion.button>
  );
};

import { ButtonHTMLAttributes } from "react";
import { cn } from "@/lib/utils";

interface WizardButtonProps extends ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: "primary" | "secondary" | "ghost";
}

export const WizardButton = ({ variant = "primary", className, children, ...props }: WizardButtonProps) => {
  return (
    <button
      className={cn(
        "w-full py-4 px-6 rounded-xl text-lg font-semibold transition-all duration-200 active:scale-[0.97] disabled:opacity-50 disabled:pointer-events-none",
        variant === "primary" && "bg-primary text-primary-foreground hover:bg-primary/90 shadow-lg",
        variant === "secondary" && "bg-secondary text-secondary-foreground hover:bg-muted border border-border",
        variant === "ghost" && "text-muted-foreground hover:text-foreground",
        className
      )}
      {...props}
    >
      {children}
    </button>
  );
};

import { WizardButton } from "../WizardButton";
